from itertools import combinations
class Solution:
    def maxValue(self, nums, k):
        n = len(nums)
        best = 0
        for idxs in combinations(range(n), 2 * k):
            first = idxs[:k]
            second = idxs[k:]
            a = 0
            for i in first:
                a |= nums[i]
            b = 0
            for i in second:
                b |= nums[i]
            if (a ^ b) > best:
                best = a ^ b
        return best

