class Solution:
    def maxValue(self, nums, k):
        n = len(nums)

        def merge(bitmask, x):
            res = 0
            m = bitmask
            while m:
                lsb = m & (-m)
                v = lsb.bit_length() - 1
                res |= 1 << (v | x)
                m ^= lsb
            return res

        prefix = [[0] * (k + 1) for _ in range(n + 1)]
        prefix[0][0] = 1
        for i in range(1, n + 1):
            x = nums[i - 1]
            prefix[i][0] = 1
            for j in range(1, k + 1):
                prefix[i][j] = prefix[i - 1][j] | merge(prefix[i - 1][j - 1], x)

        suffix = [[0] * (k + 1) for _ in range(n + 1)]
        suffix[n][0] = 1
        for i in range(n - 1, -1, -1):
            x = nums[i]
            suffix[i][0] = 1
            for j in range(1, k + 1):
                suffix[i][j] = suffix[i + 1][j] | merge(suffix[i + 1][j - 1], x)

        best = 0
        for p in range(k, n - k + 1):
            a_mask = prefix[p][k]
            b_mask = suffix[p][k]
            a = a_mask
            av = 0
            while a:
                if a & 1:
                    b = b_mask
                    bv = 0
                    while b:
                        if b & 1:
                            val = av ^ bv
                            if val > best:
                                best = val
                        b >>= 1
                        bv += 1
                a >>= 1
                av += 1
        return best

