var maxValue = function(nums, k) {
    const n = nums.length;
    const U = 128;

    function merge(arr, x) {
        const res = new Array(U).fill(false);
        for (let v = 0; v < U; v++) {
            if (arr[v]) res[v | x] = true;
        }
        return res;
    }
    function orArr(a, b) {
        const res = new Array(U).fill(false);
        for (let v = 0; v < U; v++) res[v] = a[v] || b[v];
        return res;
    }

    const prefix = new Array(n + 1);
    for (let i = 0; i <= n; i++) {
        prefix[i] = new Array(k + 1);
        for (let j = 0; j <= k; j++) prefix[i][j] = new Array(U).fill(false);
    }
    prefix[0][0][0] = true;
    for (let i = 1; i <= n; i++) {
        const x = nums[i - 1];
        prefix[i][0][0] = true;
        for (let j = 1; j <= k; j++) {
            prefix[i][j] = orArr(prefix[i - 1][j], merge(prefix[i - 1][j - 1], x));
        }
    }

    const suffix = new Array(n + 1);
    for (let i = 0; i <= n; i++) {
        suffix[i] = new Array(k + 1);
        for (let j = 0; j <= k; j++) suffix[i][j] = new Array(U).fill(false);
    }
    suffix[n][0][0] = true;
    for (let i = n - 1; i >= 0; i--) {
        const x = nums[i];
        suffix[i][0][0] = true;
        for (let j = 1; j <= k; j++) {
            suffix[i][j] = orArr(suffix[i + 1][j], merge(suffix[i + 1][j - 1], x));
        }
    }

    let best = 0;
    for (let p = k; p <= n - k; p++) {
        const A = prefix[p][k];
        const B = suffix[p][k];
        for (let a = 0; a < U; a++) {
            if (!A[a]) continue;
            for (let b = 0; b < U; b++) {
                if (B[b]) {
                    const val = a ^ b;
                    if (val > best) best = val;
                }
            }
        }
    }
    return best;
};
